sql:
SELECT method_id, COUNT(usage_id) AS total_usages
FROM method_usage
GROUP BY method_id;

SELECT COUNT(*)
FROM method_usage
WHERE method_id = 1;

SELECT COUNT(*)
FROM method_categories
WHERE category_name = 'Permanent Methods';

