sql:
SELECT method_label
FROM contraceptive_methods
WHERE method_id = 1;

SELECT category_id, COUNT(*) AS method_count
FROM contraceptive_methods
GROUP BY category_id;

SELECT LN(SUM(frequency)) AS log_frequency
FROM method_usage
WHERE method_id = 0;
